<template>
  <div class="flex-direction-column">
    <!-- 底盘信息部分 -->
    <div class="g-page-container-with-header">
      <div class="container-header flex-space-between">
        <span class="title">{{ chassisData.devdesp?.toUpperCase() }}</span>
      </div>
      <div class="container-content">
        <div class="g-section-layout">
          <!-- 第一个section -->
          <div class="section">
            <div class="g-double-column-layout">
              <div class="column">
                <div class="g-kv-pair">
                  <div class="label">设备ID</div>
                  <div class="value">
                    {{ getColumnValue(chassisData, 'devid') }}
                  </div>
                </div>
                <div class="g-kv-pair">
                  <div class="label">设备名称</div>
                  <div class="value">
                    {{ getColumnValue(chassisData, 'devname') }}
                  </div>
                </div>
              </div>
              <div class="column">
                <div class="g-kv-pair">
                  <div class="label">设备类型</div>
                  <div class="value">
                    {{ getColumnValue(chassisData, 'devtype') }}
                  </div>
                </div>
                <div class="g-kv-pair">
                  <div class="label">设备描述</div>
                  <div class="value">
                    {{ getColumnValue(chassisData, 'devdesp') }}
                  </div>
                </div>
              </div>
            </div>
          </div>
          <!-- 第二个section -->
          <div class="section">
            <div class="g-double-column-layout">
              <div class="column">
                <div
                  class="g-kv-pair"
                  v-for="(label, key) in warningLabels"
                  :key="key"
                >
                  <div class="label">{{ label }}</div>
                  <div class="value">
                    {{ getColumnValue(chassisData, key) }}
                  </div>
                </div>
              </div>
              <!-- <div class="column">
                <div
                  class="g-kv-pair"
                  v-for="(label, key) in manufacturerLabels"
                  :key="key"
                >
                  <div class="label">{{ label }}</div>
                  <div class="value">
                    {{ getColumnValue(chassisData, key) }}
                  </div>
                </div>
              </div> -->
            </div>
          </div>
        </div>
      </div>
    </div>

    <!-- 报错表格部分 -->
    <div class="g-page-container">
      <div class="g-table">
        <!-- 表头 -->
        <div class="cell flex-space-between header">
          <div
            v-for="(label, index) in errorLabels"
            :key="index"
            class="name bg"
            :class="label.class"
          >
            {{ label.text }}
          </div>
        </div>
        <div
          class="cell flex-space-between"
          v-for="(item, index) in paginatedErrors"
          :key="index"
        >
          <div class="name error-id">{{ item.id }}</div>
          <div class="name error-component">{{ item.component }}</div>
          <div class="name error-code">{{ item.errorCode }}</div>
          <div class="name error-level">{{ item.level }}</div>
          <div class="name error-message">{{ item.message }}</div>
        </div>
      </div>
      <pagination
        :total="chassisData.baseErrorList?.length || 0"
        @change="handlePageChange"
      />
    </div>
  </div>
</template>

<script setup>
import { ref, computed, watch } from 'vue'
import { storeToRefs } from 'pinia'
import { useWslStore } from '@/store/modules/ws.js'
import { useCommand } from '@/hooks/useCommand.js'

const store = useWslStore()
const { received, isConnected } = storeToRefs(store)
const { sendGetStatusData } = useCommand(store)

// 等socket连接后发送13命令获取数据
watch(
  () => isConnected.value,
  (newStatus) => {
    if (newStatus) {
      sendGetStatusData('chassis')
    }
  },
  { immediate: true }
)

// 标签定义
// const manufacturerLabels = {
//   manufacturerId: '厂商ID',
//   manufacturerName: '厂商名称',
//   modelId: '模型ID',
//   modelName: '模型名称',
//   deviceId: '设备ID',
//   hardwareVersion: '硬件版本',
//   softwareVersion: '软件版本'
// }

const warningLabels = {
  hasWarning: '告警信息',
  hasError: '报错信息',
  hasFatal: '致命信息'
}

const errorLabels = [
  { text: '报错ID', class: 'error-id' },
  { text: '报错组件', class: 'error-component' },
  { text: '报错码', class: 'error-code' },
  { text: '报错级别', class: 'error-level' },
  { text: '报错信息', class: 'error-message' }
]

// 获取底盘数据
const chassisData = computed(() => {
  const data = received.value?.statusData?.chassisDataList?.[0]
  if (!data || data.length === 0) {
    return {
      devdesp: '暂无'
    }
  }
  return data
})

const getColumnValue = (data, key) => {
  const value = data[key]
  return value === null || value === undefined || value === '' ? '-' : value
}

// 分页相关
const pageSize = ref(10)
const currentPage = ref(1)

// 分页后的错误列表
const paginatedErrors = computed(() => {
  const errorList = chassisData.value?.baseErrorList || []
  const start = (currentPage.value - 1) * pageSize.value
  const end = start + pageSize.value
  return errorList.slice(start, end)
})

const handlePageChange = (val) => {
  currentPage.value = val.page
  pageSize.value = val.size
}
</script>

<style lang="less" scoped>
.name {
  &.error-id,
  &.error-component,
  &.error-code,
  &.error-level {
    width: 6.25rem;
  }

  &.error-message {
    width: 14rem;
  }
}
</style>
